package com.google.gson.internal;
import com.google.gson.JsonIOException;
import com.google.gson.JsonNull;
import com.google.gson.JsonParseException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.EOFException;
import java.io.Writer;
import java.util.Objects;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_callsTypeAdaptersJsonElementWrite() throws IOException, ReflectiveOperationException {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> mockedTypeAdapters = Mockito.mockStatic(TypeAdapters.class)) {
      // Use reflection to get the JSON_ELEMENT field type (TypeAdapter<JsonElement>)
      java.lang.reflect.Field jsonElementField = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
      jsonElementField.setAccessible(true);
      Object jsonElementAdapterMock = mock(jsonElementField.getType());

      // Mock the static field JSON_ELEMENT to return our mock
      mockedTypeAdapters.when(() -> jsonElementField.get(null)).thenReturn(jsonElementAdapterMock);

      // Use reflection to get the write method and stub it
      java.lang.reflect.Method writeMethod = jsonElementAdapterMock.getClass().getMethod("write", JsonWriter.class, JsonElement.class);
      doNothing().when(jsonElementAdapterMock).write(writer, element);

      // Call the method under test
      Streams.write(element, writer);

      // Verify that write was called
      verify(jsonElementAdapterMock).write(writer, element);
    }
  }
}
